from pydantic import BaseModel, Field, EmailStr
from google_adk.tools import tool

class TicketInput(BaseModel):
    user_email: EmailStr = Field(description="Customer support email address")
    urgency: str = Field(description="Ticket urgency: LOW, MEDIUM, or HIGH")

@tool
def create_support_ticket(ticket: TicketInput) -> str:
    # Executed code
    return f"Created ticket for {ticket.user_email} with urgency {ticket.urgency}"
